const puppeteer = require('puppeteer');

let browser;
try {
  browser = await puppeteer.launch({
    executablePath: '/usr/bin/chromium-browser',
    headless: true,
    args: [
      '--no-sandbox',
      '--disable-setuid-sandbox',
      '--disable-dev-shm-usage',
      '--disable-gpu'
    ]
  });

  const page = await browser.newPage();
  await page.goto('https://httpbin.org/get', { 
    waitUntil: 'domcontentloaded',
    timeout: 30000 
  });

  const title = await page.title();
  const url = page.url();

  return { 
    success: true, 
    title, 
    url,
    timestamp: new Date().toISOString()
  };

} catch (error) {
  return { 
    success: false, 
    error: error.message
  };
} finally {
  if (browser) {
    await browser.close();
  }
}

const puppeteer = require('puppeteer');

async function googleSearch() {
  let browser = null;

  try {
    // Browser mit Docker-optimierten Argumenten
    browser = await puppeteer.launch({
      executablePath: '/usr/bin/chromium-browser',
      args: [
        '--no-sandbox',
        '--disable-setuid-sandbox', 
        '--disable-dev-shm-usage',
        '--disable-gpu',
        '--disable-web-security',
        '--no-first-run'
      ],
      headless: true
    });

    const page = await browser.newPage();
    await page.setViewport({ width: 1280, height: 800 });

    // Zu Google navigieren
    await page.goto('https://www.google.com', { 
      waitUntil: 'domcontentloaded',
      timeout: 15000 
    });

    // Cookie-Banner akzeptieren (falls vorhanden)
    try {
      await page.waitForSelector('button[id="L2AGLb"]', { timeout: 3000 });
      await page.click('button[id="L2AGLb"]');
      await page.waitForTimeout(1000);
    } catch (cookieError) {
      // Cookie-Banner nicht gefunden, weitermachen
    }

    // Suchbegriff aus Input oder Standard verwenden
    const searchTerm = $input.first()?.json?.searchTerm || 'n8n automation';

    await page.waitForSelector('input[name="q"]');
    await page.type('input[name="q"]', searchTerm);
    await page.keyboard.press('Enter');

    // Auf Suchergebnisse warten
    await page.waitForSelector('div#search', { timeout: 10000 });

    // Erstes Suchergebnis extrahieren
    const firstResult = await page.evaluate(() => {
      // Ersten Link finden (verschiedene Selektoren probieren)
      const selectors = ['div#search h3', '.yuRUbf h3', '.tF2Cxc h3', 'div.g h3'];
      let firstLink = null;

      for (const selector of selectors) {
        const element = document.querySelector(selector);
        if (element) {
          firstLink = element.closest('a');
          break;
        }
      }

      const link = firstLink ? firstLink.href : null;
      const title = firstLink ? firstLink.querySelector('h3')?.textContent : null;

      // Erstes Bild finden
      const firstImage = document.querySelector('div#search img');
      const imageSrc = firstImage ? firstImage.src : null;

      return { link, title, imageSrc };
    });

    // Screenshot der Suchergebnisse
    const screenshotBuffer = await page.screenshot({ 
      fullPage: false,
      type: 'png'
    });

    // ✅ n8n-konformes Return-Format (verhindert read-only errors)
    return [{
      json: {
        success: true,
        searchTerm: searchTerm,
        firstResult: {
          link: firstResult.link,
          title: firstResult.title,
          image: firstResult.imageSrc
        },
        timestamp: new Date().toISOString()
      },
      binary: {
        screenshot: {
          data: screenshotBuffer.toString('base64'),
          mimeType: 'image/png',
          fileName: `google-search-${searchTerm.replace(/[^a-zA-Z0-9]/g, '-')}.png`
        }
      }
    }];

  } catch (err) {
    console.log();
    // ✅ Korrekte Error-Behandlung (verhindert "read only property" Fehler)
    const errorMessage = String(err.message || err || 'Unbekannter Fehler');

    return [{
      json: {
        success: false,
        error: errorMessage,
        searchTerm: $input.first()?.json?.searchTerm || 'n8n automation',
        timestamp: new Date().toISOString()
      }
    }];
  } finally {
    if (browser) {
      try {
        await browser.close();
      } catch (closeError) {
        // Browser-Schließung-Fehler ignorieren
      }
    }
  }
}

// Funktion ausführen
return await googleSearch();
